import{c as a,a7 as l,y as r,B as i}from"./chunks/framework.BYQtDGaq.js";const f=JSON.parse('{"title":"Prefill-Decode 解耦架构","description":"解析 LLM 推理中 Prefill 与 Decode 阶段的资源差异及解耦部署策略，以实现更优的硬件利用与延迟控制。","frontmatter":{"title":"Prefill-Decode 解耦架构","description":"解析 LLM 推理中 Prefill 与 Decode 阶段的资源差异及解耦部署策略，以实现更优的硬件利用与延迟控制。"},"headers":[],"relativePath":"inference/optimization/pd-disaggregation.md","filePath":"inference/optimization/pd-disaggregation.md","lastUpdated":1782721961000}'),t={name:"inference/optimization/pd-disaggregation.md"};function o(d,e,n,s,c,h){return l(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="prefill-decode-解耦架构" tabindex="-1">Prefill-Decode 解耦架构 <a class="header-anchor" href="#prefill-decode-解耦架构" aria-label="Permalink to “Prefill-Decode 解耦架构”">​</a></h1><p>大型语言模型的推理过程通常分为两个差异显著的阶段：<strong>Prefill（预填充）</strong> 与 <strong>Decode（解码）</strong>。将这两个阶段部署到不同的硬件资源池中，可以更好地匹配各自的计算特性，从而提升资源利用率、降低延迟并支持更长上下文。</p><h2 id="_1-两个阶段的特点" tabindex="-1">1. 两个阶段的特点 <a class="header-anchor" href="#_1-两个阶段的特点" aria-label="Permalink to “1. 两个阶段的特点”">​</a></h2><h3 id="_1-1-prefill-阶段" tabindex="-1">1.1 Prefill 阶段 <a class="header-anchor" href="#_1-1-prefill-阶段" aria-label="Permalink to “1.1 Prefill 阶段”">​</a></h3><p>Prefill 阶段并行处理整个输入 Prompt，计算 Key/Value 并写入 KV Cache，然后生成第一个输出 Token。</p><ul><li><strong>计算特性</strong>：高度并行的矩阵运算，属于<strong>计算密集型</strong>任务。</li><li><strong>主要开销</strong>：注意力计算与 KV Cache 构建。</li><li><strong>影响指标</strong>：首 Token 延迟（TTFT）。</li></ul><h3 id="_1-2-decode-阶段" tabindex="-1">1.2 Decode 阶段 <a class="header-anchor" href="#_1-2-decode-阶段" aria-label="Permalink to “1.2 Decode 阶段”">​</a></h3><p>Decode 阶段基于 KV Cache 与已生成 Token，逐个自回归地预测下一个 Token。</p><ul><li><strong>计算特性</strong>：串行生成，每次只处理一个 Token，受限于内存带宽，属于<strong>内存密集型</strong>任务。</li><li><strong>主要开销</strong>：读取不断增长的 KV Cache 与生成下一个 Token。</li><li><strong>影响指标</strong>：Token 间延迟（ITL / TPOT）。</li></ul><h2 id="_2-混合部署的问题" tabindex="-1">2. 混合部署的问题 <a class="header-anchor" href="#_2-混合部署的问题" aria-label="Permalink to “2. 混合部署的问题”">​</a></h2><p>在传统的单体式架构中，Prefill 与 Decode 共享同一 GPU，会相互干扰：</p><ul><li>当 GPU 被计算密集的 Prefill 占用时，Decode 必须等待，导致 ITL 上升。</li><li>当 GPU 被内存密集的 Decode 占用时，Prefill 被阻塞，导致 TTFT 变长。</li><li>两个阶段适合的并行策略不同：Prefill 适合张量并行降低延迟，Decode 适合流水线并行提升吞吐。</li></ul><p>因此，将两者混合部署难以同时优化 TTFT 与 ITL。</p><h2 id="_3-什么是-prefill-decode-解耦" tabindex="-1">3. 什么是 Prefill-Decode 解耦 <a class="header-anchor" href="#_3-什么是-prefill-decode-解耦" aria-label="Permalink to “3. 什么是 Prefill-Decode 解耦”">​</a></h2><p>Prefill-Decode 解耦将两个阶段部署到不同的硬件资源池中：</p><ul><li><strong>Prefill 集群</strong>：配备高算力、适合大规模并行计算的 GPU，侧重高吞吐。</li><li><strong>Decode 集群</strong>：配备大显存、高内存带宽的 GPU，侧重低延迟。</li></ul><p>两者通过高速网络传输 KV Cache，使请求在 Prefill 完成后无缝移交到 Decode 节点继续生成。</p><h2 id="_4-解耦的优势" tabindex="-1">4. 解耦的优势 <a class="header-anchor" href="#_4-解耦的优势" aria-label="Permalink to “4. 解耦的优势”">​</a></h2><div class="vp-table-wrapper"><table tabindex="0"><thead><tr><th>优势</th><th>说明</th></tr></thead><tbody><tr><td>专用资源分配</td><td>两个阶段可独立调度与扩展，根据负载动态分配资源。</td></tr><tr><td>并行执行</td><td>Prefill 与 Decode 不再相互阻塞，提升并发性与整体吞吐。</td></tr><tr><td>独立优化</td><td>可分别采用不同的并行策略、量化方式与调度算法。</td></tr><tr><td>缓存复用</td><td>多轮对话或 Agent 工作流中，KV Cache 可在 Decode 节点复用，降低重复 Prefill。</td></tr></tbody></table></div><p>多个开源框架正在积极探索 PD 解耦，包括 <a href="https://github.com/sgl-project/sglang/issues/4655" target="_blank" rel="noreferrer">SGLang</a>、<a href="https://docs.vllm.ai/en/latest/features/disagg_prefill.html" target="_blank" rel="noreferrer">vLLM</a>、<a href="https://docs.nvidia.com/dynamo/latest/architecture/disagg_serving.html" target="_blank" rel="noreferrer">NVIDIA Dynamo</a> 与 <a href="https://docs.google.com/document/d/1FNN5snmipaTxEA1FGEeSH7Z_kEqskouKD1XYhVyTHr8/edit" target="_blank" rel="noreferrer">llm-d</a>。</p><h2 id="_5-面临的挑战" tabindex="-1">5. 面临的挑战 <a class="header-anchor" href="#_5-面临的挑战" aria-label="Permalink to “5. 面临的挑战”">​</a></h2><h3 id="_5-1-额外通信开销" tabindex="-1">5.1 额外通信开销 <a class="header-anchor" href="#_5-1-额外通信开销" aria-label="Permalink to “5.1 额外通信开销”">​</a></h3><p>Prefill 与 Decode 分离后，需要将 KV Cache 从 Prefill 节点传输到 Decode 节点，网络延迟与带宽可能成为瓶颈。</p><p><strong>应对</strong>：</p><ul><li>采用超低延迟、高带宽网络（如 NVLink、InfiniBand、RDMA）。</li><li>按 Token 粒度分区，最大化数据与 Decode 节点的邻近性。</li></ul><h3 id="_5-2-调度复杂度提升" tabindex="-1">5.2 调度复杂度提升 <a class="header-anchor" href="#_5-2-调度复杂度提升" aria-label="Permalink to “5.2 调度复杂度提升”">​</a></h3><p>系统需实时协调双队列任务分配，否则 Decode 可能空等 Prefill 结果，或 Prefill 资源被 Decode 阻塞。</p><p><strong>应对</strong>：</p><ul><li>优先级调度：优先执行 Prefill 以保障 TTFT，公平调度 Decode 以维持 TPOT。</li><li>流水线并行：重叠 Prefill 与 Decode 执行，减少空闲等待。</li></ul><h3 id="_5-3-实现复杂度高" tabindex="-1">5.3 实现复杂度高 <a class="header-anchor" href="#_5-3-实现复杂度高" aria-label="Permalink to “5.3 实现复杂度高”">​</a></h3><p>框架与调度器需支持流水线操作、KV Cache 输出与异步执行，维护难度高于单机单 GPU 方案。</p><p><strong>应对</strong>：</p><ul><li>使用支持 PD 解耦的成熟框架（如 SGLang、vLLM、Dynamo）。</li><li>通过 RDMA 与零拷贝技术降低传输开销。</li></ul><h3 id="_5-4-高内存占用" tabindex="-1">5.4 高内存占用 <a class="header-anchor" href="#_5-4-高内存占用" aria-label="Permalink to “5.4 高内存占用”">​</a></h3><p>Prefill 阶段可能同时处理多个请求，Decode 阶段需保留完整 KV Cache，二者均带来显著内存压力。</p><p><strong>应对</strong>：</p><ul><li>分层存储：热数据保留在 GPU，温/冷数据存储在 CPU 或 NVMe。</li><li>内存池管理：通过复用减少动态分配开销。</li><li>RDMA 加速：在分布式场景中实现快速 KV Cache 传输。</li></ul><h2 id="_6-总结" tabindex="-1">6. 总结 <a class="header-anchor" href="#_6-总结" aria-label="Permalink to “6. 总结”">​</a></h2><p>Prefill-Decode 解耦通过将计算密集型与内存密集型阶段分离，能够降低延迟、提高吞吐量并优化内存使用。随着模型规模与上下文长度的增长，这一方法已成为保持 LLM 推理系统响应能力与可扩展性的关键技术。</p>',39)])])}const g=a(t,[["render",o]]);export{f as __pageData,g as default};
